// Отримуємо масив лідів (усі items з попереднього вузла)
const data = $input.all().map(item => item.json);

// 1. Кількість лідів на кожному етапі (Lead_Status)
const byStage = {};
// 2. Кількість лідів по кожному менеджеру (Owner.name)
const byOwner = {};
// 3. Лічильник лідів зі статусом "New"
let newLeadsCount = 0;

for (const lead of data) {
  // --- Етап (Lead_Status) ---
  // нормалізуємо: null -> "Без статусу", різний регістр -> один ключ
  const rawStage = lead.Lead_Status;
  const stage = (rawStage === null || rawStage === undefined || rawStage === "")
    ? "Без статусу"
    : String(rawStage).trim();

  byStage[stage] = (byStage[stage] || 0) + 1;

  // --- Менеджер (Owner) ---
  const ownerName = lead.Owner?.name || "Без власника";
  byOwner[ownerName] = (byOwner[ownerName] || 0) + 1;

  // --- Окремо: статус "New" (нечутливо до регістру) ---
  if (stage.toLowerCase() === "new") {
    newLeadsCount++;
  }
}

// Сортуємо за спаданням для зручності
const sortDesc = (obj) =>
  Object.fromEntries(Object.entries(obj).sort((a, b) => b[1] - a[1]));

const result = {
  total_leads: data.length,
  new_leads_count: newLeadsCount,
  by_stage: sortDesc(byStage),
  by_owner: sortDesc(byOwner),
};

// Повертаємо як один item
return [{ json: result }];

